  2777 |   Value *FalseVal = SI.getFalseValue();
  2778 | 
  2779 |   CmpPredicate Pred;
  2780 |   Value *Op, *RemRes, *Remainder;
  2781 |   const APInt *C;
  2782 |   bool TrueIfSigned = false;
  2783 | 
